+fn resolve_http_bearer_token_for_serve(
+    current_token: Option<&str>,
+    env_file: Option<&str>,
+) -> Option<String> {
+    if current_token.is_some_and(|token| !token.trim().is_empty()) {
+        return None;
+    }
+    let path = env_file?;
+    load_env_file_value(Path::new(path), "HTTP_BEARER_TOKEN")
+}
